const NAME_OVERRIDES = {
  "FARFETCH_D": "Farfetch'd",
  "MR__MIME": "Mr. Mime",
  "HO_OH": "Ho-Oh",
  "NIDORAN_F": "Nidoran♀",
  "NIDORAN_M": "Nidoran♂",
  "PORYGON2": "Porygon2"
};

export function formatSpeciesName(symbol) {
  if (NAME_OVERRIDES[symbol]) return NAME_OVERRIDES[symbol];
  return symbol
    .split('_')
    .map((part) => part.charAt(0) + part.slice(1).toLowerCase())
    .join(' ');
}

function speciesEntryFor(dexNo) {
  if (!Number.isInteger(dexNo) || dexNo < 1 || dexNo > NATIONAL_DEX_MAX) return null;
  return SPECIES_DATA[dexNo - 1] ?? null;
}

export function getSpeciesByDexNo(catalog, dexNo) {
  return catalog?.byDexNo?.get?.(dexNo) ?? speciesEntryFor(dexNo);
}

// In Gen 2 Crystal the party struct's MON_SPECIES byte stores the national dex
// number directly, so internal id == dex no. Callers that still go through
// this helper get the same answer as getSpeciesByDexNo.
export function getSpeciesByInternalId(catalog, internalSpeciesId) {
  return getSpeciesByDexNo(catalog, internalSpeciesId);
}

export function getGen2SpeciesCatalog() {
  const byDexNo = new Map();
  const byInternalId = new Map();
  for (const entry of SPECIES_DATA) {
    byDexNo.set(entry.dexNo, entry);
    byInternalId.set(entry.dexNo, entry);
  }
  return {
    pokedex: SPECIES_DATA.slice(),
    byDexNo,
    byInternalId,
    validation: {
      pikachuCatchRate: byDexNo.get(25)?.catchRate ?? null,
      mewtwoCatchRate: byDexNo.get(150)?.catchRate ?? null,
      celebiCatchRate: byDexNo.get(251)?.catchRate ?? null,
      typhlosionBaseSat: byDexNo.get(157)?.baseSat ?? null,
    },
  };
}

const browserExports = {
  NATIONAL_DEX_MAX,
  POKEDEX_SYMBOLS,
  SPECIES_DATA,
  TYPE_NAMES,
  formatSpeciesName,
  getGen2SpeciesCatalog,
  getSpeciesByDexNo,
  getSpeciesByInternalId,
};

if (typeof window !== 'undefined') {
  window.PokeBellsGen2Species = browserExports;
}
